// MOCK API: Fetching the close prices for 3 monitored stocks.
// This simulates the n8n data structure exactly.

return [
  {
    "json": {
      "ticker": "RELIANCE",
      "prevClose": 2500,
      "currentClose": 2565
    }
  },
  {
    "json": {
      "ticker": "TCS",
      "prevClose": 3500,
      "currentClose": 3490
    }
  },
  {
    "json": {
      "ticker": "HDFCBANK",
      "prevClose": 1600,
      "currentClose": 1545
    }
  }
];

const alerts = [];

// Loop through the 3 stocks passed from the previous node
for (const item of $input.all()) {
  const stock = item.json;

  // Calculate percentage change
  const percentChange = ((stock.currentClose - stock.prevClose) / stock.prevClose) * 100;

  // Check if absolute change is strictly greater than 2%
  if (Math.abs(percentChange) > 2) {
    const icon = percentChange > 0 ? '📈 UP' : '📉 DOWN';
    alerts.push(`${icon}: <strong>${stock.ticker}</strong> moved <strong>${Math.abs(percentChange).toFixed(2)}%</strong> (From Rs. ${stock.prevClose} to Rs. ${stock.currentClose})`);
  }
}

// If alerts were generated, format the email and pass it to the next node.
// If no stocks moved >2%, returning an empty array [] stops the workflow here safely.
if (alerts.length > 0) {
  const emailBody = `<h3>🚨 Stock Alert: Significant Movements Detected</h3><hr><br><p>${alerts.join('<br><br>')}</p>`;
  return [{ json: { emailBody } }];
}

return [];
